import kotlin.test.*
import kotlin.time.*
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.nanoseconds

class DelayNanoTest : TestBase() {

    @Test
    fun testDelayDurationCoercion() = runTest {
        if (isJavaAndWindows) return@runTest

        repeat(5) {
            val expectedDuration = 998.milliseconds + 902752.nanoseconds
            val start = TimeSource.Monotonic.markNow()
            delay(expectedDuration)
            val actualDuration = start.elapsedNow()

            // If the bug exists, delay(expectedDuration) calls delay(998ms)
            // So actualDuration will be around 998ms.
            // expectedDuration is ~998.9ms.
            // So actualDuration < expectedDuration.

            assertTrue(actualDuration >= expectedDuration, "Actual duration $actualDuration should be >= expected duration $expectedDuration")
        }
    }
}
